const inp = $('Input from MAIN').first().json;
const sys = Buffer.from($('Load System').first().json.content,'base64').toString('utf-8');
let   usr = Buffer.from($('Load User').first().json.content,'base64').toString('utf-8');
const a3out = inp.agent_output||{};
const a1out = inp.a1_audit||{};
const a2out = inp.a2_glossary||{};
const vars = {
  course_id: inp.course_id||'',
  source_language: inp.source_language||'fr',
  target_language: inp.target_language||'en-US',
  domain: inp.detected_domain||'',
  audience: inp.audience||'',
  source_content: inp.html||inp.source_html||'',
  a3_gold_master: a3out.revised_content||'',
  a1_cultural_flags: JSON.stringify(a1out.cultural_flags||(inp.a1_outputs||[]).flatMap(a=>a&&a.cultural_flags||[])||[]),
  a2_terminology_decisions: JSON.stringify(a2out.translation_decisions||inp.translation_decisions||[]),
  common_glossary: JSON.stringify(inp.common_glossary||[]),
  constraints: JSON.stringify(inp.constraints||[])
};
Object.entries(vars).forEach(([k,v]) => {
  usr = usr.replace(new RegExp('\\{{'+k+'\\}}','g'), String(v));
});
return [{json:{
  system_prompt: sys, user_message: usr,
  model: 'gpt-5.2', temperature: 0.3, max_tokens: 16000,
  custom_id: (inp.course_id||'x')+'-ch'+(inp.chapter_index||0)+'-ck'+(inp.chunk_index||1)+'-a4culturaladapter',
  agent_name: 'A4 Cultural Adapter', course_id: inp.course_id,
  chapter_index: inp.chapter_index, chunk_index: inp.chunk_index,
  pipeline_meta: inp.pipeline_meta||{}
}}];

const p = $input.first().json;
const orig = $('Input from MAIN').first().json;
const a4out = p.agent_output||{};
if(p.status==='failed'||p.status==='timed_out')
  return [{json:{status:'error',agent:'A4 Cultural Adapter',error:p.error,escalation:true,
    course_id:p.course_id||orig.course_id,chapter_index:orig.chapter_index||0,chunk_index:orig.chunk_index||1}}];
return [{json:{
  status:'ok', agent:'A4 Cultural Adapter', agent_output:a4out,
  course_id:p.course_id||orig.course_id,
  chapter_index:orig.chapter_index||0, chunk_index:orig.chunk_index||1,
  pipeline_meta:p.pipeline_meta||{},
  translated_html:a4out.adapted_content||a4out.adapted_html||orig.html||'',
  a4_swap_log:a4out.swap_log||a4out.decision_log||[],
  html:orig.html||orig.source_html||'', source_html:orig.html||orig.source_html||'',
  a1_audit:orig.a1_audit||{}, a2_glossary:orig.a2_glossary||{},
  a1_outputs:orig.a1_outputs||[], common_glossary:orig.common_glossary||[],
  domain_validated_tm:orig.domain_validated_tm||[], domain_unvalidated_tm:orig.domain_unvalidated_tm||[],
  detected_domain:orig.detected_domain||'', source_language:orig.source_language||'fr',
  target_language:orig.target_language||'en-US', target_course_id:orig.target_course_id||'',
  score_target:orig.score_target||90, iteration:orig.iteration||1,
  preceding_context:orig.preceding_context||'', enabled_modules:orig.enabled_modules||{}
}}];

